  ('aboriginal-6f0ba476-moex-00547', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '假設經濟體系中有兩位消費者（A和B），兩種財貨（X和Y）。消費者A的初始稟賦為（X=30, Y=20）而消費者B的初始稟賦為（X=20,Y=30）。兩位消費者的效用函數皆為U(X,Y)=XY。如 果政府的重分配政策是將消費者A的4單位X財貨移轉給消費者B。為了滿足柏瑞圖改善（Pareto improvement）的定義，政府需要同時將幾單位的Y財貨從消費者B移轉給消費者A？', '["1單位的Y財貨", "2單位的Y財貨", "3單位的Y財貨", "4單位的Y財貨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "7948d6976ec8", "answer_pdf_sha1": "db992a01dd7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00548', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-111-d3ff7f6b', 'sub-aboriginal-6f0ba476-08', NULL, 'single_choice', '社會整體最適污染量的決定原則應為：', '["污染量為零", "污染量成長率為零", "降低污染的社會邊際成本等於降低污染的社會邊際效益", "污染的社會總成本等於污染的社會總效益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "7948d6976ec8", "answer_pdf_sha1": "db992a01dd7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "506", "s": "1111", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
